const body = $input.first().json.body || {};
const cmd = body.command || body.cmd || null;
const path = body.path || null;

const ALLOWED_CMD_PREFIXES = [
  'cat ', 'ls ', 'wc ', 'wc -l', 'echo ',
  'find /opt/gda-command', 'find /etc/nginx', 'find /var/log',
  'find /root/gda-frontend', 'find /root/n8n-envision',
  'tail ', 'grep ', 'cat /etc/nginx',
  'tee ', 'python3 ', 'sed ', 'bash -c ', 'printf ',
  'git -C ', 'git --version', 'git config', 'git clone', 'git init', 'git remote', 'git add', 'git commit', 'git push', 'git pull', 'git branch', 'git checkout', 'git status', 'git log'
];
const ALLOWED_PATH_PREFIX = '/opt/gda-command/src/';

if (path) {
  if (!path.startsWith(ALLOWED_PATH_PREFIX)) {
    throw new Error('Command not permitted: path outside allowed directory');
  }
  return $input.all();
}

if (cmd) {
  const allowed = ALLOWED_CMD_PREFIXES.some(prefix => cmd.startsWith(prefix)) ||
    /^python3 (\/tmp\/|\-c )/.test(cmd);
  if (!allowed) {
    throw new Error('Command not permitted: ' + cmd);
  }
  return $input.all();
}

throw new Error('Command not permitted: no cmd or path provided');
